// ── Helper function ──
// Used by both app.html and hub.html
// Returns translated string for key, falls back to EN, falls back to key name itself
function t(key) {
  const lang = window.__reorderlyLang || 'en';
  return (LANG[lang] && LANG[lang][key]) || LANG.en[key] || key;
}
